export declare const GET_LEETCODE_USER_STATS_QUERY = "\n  query getUserProfile($username: String!) {\n    matchedUser(username: $username) {\n      username\n      githubUrl\n      twitterUrl\n      linkedinUrl\n      profile {\n        realName\n        userAvatar\n        ranking\n        reputation\n        starRating\n        aboutMe\n        company\n        countryName\n        school\n      }\n      submitStats: submitStatsGlobal {\n        acSubmissionNum {\n          difficulty\n          count\n          submissions\n        }\n      }\n      badges {\n        id\n        name\n        shortName\n        displayName\n        icon\n      }\n      languageProblemCount {\n        languageName\n        problemsSolved\n      }\n    }\n    userContestRanking(username: $username) {\n      attendedContestsCount\n      rating\n      globalRanking\n      totalParticipants\n      topPercentage\n    }\n    allQuestionsCount {\n      difficulty\n      count\n    }\n  }\n";
